
import {
  defineComponent,
  onDeactivated,
  provide,
  reactive,
  ref,
  toRefs,
  watch,
} from "vue";
import AmultitaskingSearch from "../../../components/Amultitasking/AmultitaskingSearch.vue";
import AmultitaskingTable from "../../../components/Amultitasking/AmultitaskingTable.vue";
import { getSampleList } from "@/server/http/api/Amultitasking";
export default defineComponent({
  name: "Collarsample",
  components: { AmultitaskingSearch, AmultitaskingTable },
  setup() {
    let dataList: any = ref([]);
    // 筛选条件
    const total = ref(0);
    let options = reactive({
      pageNum: 1,
      pageSize: 10,
    });
    let formState: any = {};
    function filterCollarsample(form: any) {
      Object.assign(formState, form);
      Object.assign(formState, options);

      getSampleList(formState).then((res: any) => {
        Object.assign(formState, options);
        if (res.data.code === 200) {
          dataList.value = res.data.data.list;
          total.value = res.data.data.total;
        }
      });
    }
    watch(options, () => {
      getSampleList(formState).then((res: any) => {
        if (res.data.code === 200) {
          dataList.value = res.data.data.list;
          total.value = res.data.data.total;
        }
      });
    });

    function updateCollarsample() {
      getSampleList(formState).then((res: any) => {
        if (res.data.code === 200) {
          dataList.value = res.data.data.list;
          total.value = res.data.data.total;
        }
      });
    }
    provide("updateCollarsample", updateCollarsample);
    return {
      filterCollarsample,
      dataList,
      updateCollarsample,
      total,
      ...toRefs(options),
    };
  },
});
